create table if not exists public.exercicios (
 id uuid primary key default gen_random_uuid(),
 exercisedb_id text not null,
 nome_en text not null,
 nome_pt text not null,
 body_part text not null,
 target text not null,
 equipment text not null,
 secondary_muscles text[],
 instrucoes_pt text[],
 dificuldade text check (dificuldade in ('beginner','intermediate','advanced')),
 categoria text,
 gif_url_local text,
 video_url text,
 ativo boolean default true,
 criado_em timestamptz default now()
);

grant select on public.exercicios to anon, authenticated;
grant all on public.exercicios to service_role;

alter table public.exercicios enable row level security;
drop policy if exists "leitura publica exercicios" on public.exercicios;
create policy "leitura publica exercicios" on public.exercicios for select using (true);

