insert into public.exercicios (exercisedb_id,nome_en,nome_pt,body_part,target,equipment,secondary_muscles,instrucoes_pt,dificuldade,categoria,ativo) values
('manual_dead_hang','Dead Hang','Suspensão (Dead Hang)','costas','antebraço, ombros, core','barra_fixa_parede',null,ARRAY['Pendurar na barra com braços estendidos. Constrói força de preensão e ativa cintura escapular.','Mantenha ombros engajados pra trás e pra baixo','Aperte firmemente a barra com toda a palma','Olhe pra frente, queixo levemente recolhido','Erros comuns: Pendurar com ombros tensionados pra cima, Soltar respiração']::text[],'beginner','preparatorio',true),
('manual_active_hang','Active Hang','Suspensão Ativa','costas','trapézio inferior, romboides','barra_fixa_parede',null,ARRAY['Suspensão com escápulas engajadas (puxadas pra trás/baixo). Pré-requisito do pull-up.','Aperte a barra forte','Puxe escápulas pra trás e pra baixo','Sensação de afastar ombros das orelhas','Erros comuns: Deixar os ombros frouxos, Curvar a lombar']::text[],'beginner','preparatorio',true),
('manual_scapular_pull_up','Scapular Pull-Up','Scapular Pull-Up','costas','trapézio inferior, romboides','barra_fixa_parede',null,ARRAY['Movimento só das escápulas, sem dobrar cotovelo. Ensina a iniciar o pull-up corretamente.','Cotovelos ESTENDIDOS o tempo todo','Apenas puxe escápulas pra baixo','Pausa curta no topo, desce controlado','Erros comuns: Dobrar cotovelo, Movimento muito rápido']::text[],'beginner','preparatorio',true),
('manual_negative_pull_up','Negative Pull-Up','Pull-Up Negativo','costas','latíssimo, bíceps','barra_fixa_parede',null,ARRAY['Subir com auxílio e descer controlado em 3-5 segundos. Constrói força excêntrica.','Sobe com ajuda da cadeira até queixo acima da barra','Tira pés e desce em 3-5 segundos','Mantém tensão até cotovelos estendidos','Erros comuns: Descer rápido demais, Soltar a barra antes do fim']::text[],'beginner','preparatorio',true),
('manual_pull_up_assistido_elastico','Band-Assisted Pull-Up','Pull-Up Assistido com Elástico','costas','latíssimo, bíceps','barra_fixa_parede',null,ARRAY['Pull-up com elástico passando pelos pés ou joelhos. Transição pro pull-up completo.','Prenda elástico na barra e passe pelo pé ou joelho','Movimento completo: queixo acima da barra','Desce controlado','Erros comuns: Elástico forte demais, Encolher os ombros no topo']::text[],'beginner','preparatorio',true),
('manual_chin_up','Chin-Up','Chin-Up (Pegada Supinada)','costas','latíssimo, bíceps','barra_fixa_parede',null,ARRAY['Pull-up com palmas viradas pra você. Mais foco em bíceps, mais fácil que pull-up.','Pegada supinada, largura dos ombros','Puxa até queixo acima da barra','Desce controlado','Erros comuns: Não atingir amplitude completa, Balançar o corpo (kipping)']::text[],'intermediate','principal',true),
('manual_pull_up','Pull-Up','Pull-Up (Pegada Pronada)','costas','latíssimo, romboides, bíceps','barra_fixa_parede',null,ARRAY['Pull-up tradicional. Movimento principal de costas com peso corporal.','Pegada pronada, levemente maior que os ombros','Puxa até queixo acima da barra','Escápulas retraídas no topo','Erros comuns: Balanço excessivo, Não chegar com queixo acima da barra']::text[],'intermediate','principal',true),
('manual_wide_pull_up','Wide Grip Pull-Up','Pull-Up com Pegada Larga','costas','latíssimo','barra_fixa_parede',null,ARRAY['Pull-up com pegada bem mais aberta. Enfatiza dorsais.','Pegada bem mais larga que ombros','Foco em sentir dorsal puxando','Subida completa','Erros comuns: Sacrificar amplitude pela carga, Levantar ombros pras orelhas']::text[],'advanced','principal',true),
('manual_archer_pull_up','Archer Pull-Up','Archer Pull-Up','costas','latíssimo, core','barra_fixa_parede',null,ARRAY['Pull-up arqueiro: um braço puxa, outro estende lateralmente. Progressão pro one-arm.','Pegada bem larga','Puxa em direção a um lado','Alterna lados em cada repetição','Erros comuns: Não chegar próximo da barra do lado puxado, Sem estabilização do braço estendido']::text[],'advanced','preparatorio',true),
('manual_hanging_knee_raise','Hanging Knee Raise','Elevação de Joelhos Pendurado','core','abdomen inferior, flexores quadril','barra_fixa_parede',null,ARRAY['Pendurado, eleva os joelhos em direção ao peito. Trabalha core completo.','Suspensão ativa antes de iniciar','Eleva joelhos juntos até altura do quadril','Desce controlado','Erros comuns: Balançar o corpo pra ganhar impulso, Não engajar o core']::text[],'intermediate','principal',true),
('manual_hanging_leg_raise','Hanging Leg Raise','Elevação de Pernas Estendidas','core','abdomen inferior','barra_fixa_parede',null,ARRAY['Pendurado, eleva pernas estendidas até a horizontal. Avançado de core.','Pernas COMPLETAMENTE estendidas','Eleva até paralelas ao chão','Movimento controlado','Erros comuns: Dobrar joelhos pra facilitar, Usar momento']::text[],'advanced','principal',true),
('manual_toes_to_bar','Toes to Bar','Pés na Barra (Toes to Bar)','core','abdomen completo','barra_fixa_parede',null,ARRAY['Pendurado, eleva pés até tocar a barra. Movimento de elite pra core.','Pernas estendidas o tempo todo','Toca a barra com a parte de cima dos pés','Desce controlado SEM relaxar core','Erros comuns: Dobrar joelhos no caminho, Não tocar a barra']::text[],'advanced','principal',true),
('manual_l_sit_hold','L-Sit Hold','L-Sit Pendurado','core','abdomen, flexores quadril, quadriceps','barra_fixa_parede',null,ARRAY['Pendurado na barra, mantém pernas estendidas paralelas ao chão. Isométrico de core.','Pernas estendidas e paralelas ao chão','Aperte o quadríceps','Mantenha respiração','Erros comuns: Dobrar joelhos pra aliviar, Pernas abaixo da linha do quadril']::text[],'advanced','principal',true),
('manual_muscle_up_progression','Muscle-Up Progression','Progressão Muscle-Up','full_body','latíssimo, peito, tríceps','barra_fixa_parede',null,ARRAY['Pull-up explosivo seguido de transição sobre a barra. Calistenia avançada.','Pegada falsa (pulso acima da barra)','Puxa explosivo bem alto, peito acima da barra','Inclina pra frente e empurra pra cima','Erros comuns: Tentar sem ter pull-up consistente acima do peito, Sem inclinação pra frente']::text[],'advanced','principal',true),
('manual_front_lever_progression','Front Lever Progression','Progressão Front Lever','core','core completo, latíssimo','barra_fixa_parede',null,ARRAY['Corpo paralelo ao chão, pendurado. Tuck → Advanced Tuck → Straddle → Full.','Comece em tuck e progride','Escápulas DEPRIMIDAS','Corpo paralelo ao chão','Erros comuns: Pular fases muito rápido, Quadril alto demais']::text[],'advanced','principal',true),
('manual_push_up_wall','Wall Push-Up','Flexão na Parede','peito','peito, tríceps','peso_corporal',null,ARRAY['Flexão em pé contra a parede. Iniciantes absolutos.','Pés afastados ~50cm da parede','Mãos na altura dos ombros, pouco mais largas','Encosta o peito na parede','Erros comuns: Cabeça pra frente e ombros pras orelhas, Mãos muito altas ou baixas']::text[],'beginner','preparatorio',true),
('manual_push_up_knees','Knee Push-Up','Flexão com Joelhos','peito','peito, tríceps','peso_corporal',null,ARRAY['Flexão tradicional apoiada nos joelhos. Transição entre parede e flexão completa.','Mãos largura ombros, dedos pra frente','Corpo reto da cabeça aos joelhos','Desce até peito quase tocar o chão','Erros comuns: Soltar o quadril, Não chegar perto do chão']::text[],'beginner','preparatorio',true),
('manual_push_up_regular','Push-Up','Flexão Regular','peito','peito, tríceps, core','peso_corporal',null,ARRAY['Flexão tradicional. Movimento fundamental pra peito, tríceps e core.','Corpo reto da cabeça aos calcanhares','Mãos abaixo dos ombros, dedos pra frente','Desce até peito a 5cm do chão','Erros comuns: Lombar arqueada ou afundada, Cotovelos abrindo 90°']::text[],'beginner','principal',true),
('manual_push_up_diamond','Diamond Push-Up','Flexão Diamante','peito','tríceps','peso_corporal',null,ARRAY['Flexão com mãos juntas formando triângulo. Foco em tríceps.','Polegares e indicadores formam triângulo','Cotovelos colados ao corpo','Toca peito no centro das mãos','Erros comuns: Mãos longe do peito, Cotovelos abrindo']::text[],'intermediate','principal',true),
('manual_push_up_decline','Decline Push-Up','Flexão Declinada','peito','peito superior, ombros','peso_corporal',null,ARRAY['Flexão com pés elevados. Mais carga no peito superior e ombros.','Pés elevados 30-50cm','Mãos no chão, ligeiramente mais largas','Mantém corpo reto','Erros comuns: Pés muito altos demais, Soltar o quadril']::text[],'intermediate','principal',true),
('manual_pike_push_up','Pike Push-Up','Flexão Pike','ombros','deltoide anterior','peso_corporal',null,ARRAY['Flexão em V invertido. Foco em ombros (substitui shoulder press).','Posição de V invertido','Cabeça desce em direção ao chão','Cotovelos descem em direção à frente','Erros comuns: Quadril baixo (vira flexão normal), Não descer cabeça perto do chão']::text[],'intermediate','principal',true),
('manual_pseudo_planche_push_up','Pseudo Planche Push-Up','Flexão Pseudo Planche','peito','peito, deltoide anterior','peso_corporal',null,ARRAY['Flexão com mãos no quadril e inclinação pra frente. Progressão pra planche.','Mãos próximas do quadril','Inclina ombros pra frente das mãos','Desce mantendo inclinação','Erros comuns: Mãos perto da cabeça, Sem inclinação pra frente']::text[],'advanced','principal',true),
('manual_squat_bodyweight','Bodyweight Squat','Agachamento Livre','pernas','quadríceps, glúteo','peso_corporal',null,ARRAY['Agachamento com peso corporal. Movimento fundamental de membro inferior.','Pés largura dos ombros, dedos levemente pra fora','Desce empurrando quadril pra trás','Coxas paralelas ou abaixo','Erros comuns: Joelhos colapsando pra dentro, Calcanhar saindo do chão, Lombar arredondada']::text[],'beginner','principal',true),
('manual_jump_squat','Jump Squat','Agachamento com Salto','pernas','quadríceps, glúteo','peso_corporal',null,ARRAY['Agachamento explosivo com salto vertical. Treina potência.','Agacha em posição de carga','Salta vertical com máxima força','Pousa suave em posição de agachamento','Erros comuns: Pouso rígido sem amortecimento, Joelhos colapsando ao pousar']::text[],'intermediate','principal',true),
('manual_pistol_squat_assisted','Assisted Pistol Squat','Pistol Squat Assistido','pernas','quadríceps, glúteo','peso_corporal',null,ARRAY['Agachamento unilateral segurando apoio. Progressão pro pistol completo.','Uma perna estendida à frente','Segura em apoio com uma mão','Desce até quadril próximo do calcanhar','Erros comuns: Calcanhar saindo do chão, Joelho colapsando']::text[],'intermediate','preparatorio',true),
('manual_pistol_squat','Pistol Squat','Pistol Squat','pernas','quadríceps, glúteo, core','peso_corporal',null,ARRAY['Agachamento numa perna só, sem apoio. Equilíbrio e força extremos.','Perna estendida à frente, paralela ao chão','Desce em rotação controlada','Sobe explosivo sem perder equilíbrio','Erros comuns: Cair pra trás, Joelho colapsando pra dentro']::text[],'advanced','principal',true),
('manual_lunge_alternado','Walking Lunge','Afundo Alternado','pernas','quadríceps, glúteo','peso_corporal',null,ARRAY['Passada à frente, agachando até joelho de trás quase tocar o chão.','Passada grande à frente','Joelho à frente alinhado com tornozelo','Joelho de trás quase toca o chão','Erros comuns: Joelho passando do tornozelo, Cair pro lado']::text[],'beginner','principal',true),
('manual_reverse_lunge','Reverse Lunge','Afundo Reverso','pernas','quadríceps, glúteo','peso_corporal',null,ARRAY['Como o afundo, mas dando passo PRA TRÁS. Mais fácil pra joelhos sensíveis.','Da posição em pé, passo grande pra trás','Desce joelho de trás','Empurra perna da frente pra voltar','Erros comuns: Passada curta, Tronco inclinado pra frente']::text[],'beginner','principal',true),
('manual_glute_bridge','Glute Bridge','Ponte de Glúteo','pernas','glúteo, posterior coxa','peso_corporal',null,ARRAY['Deitado, eleva o quadril ativando glúteos. Excelente pra iniciantes.','Deitado, joelhos dobrados, pés apoiados','Eleva quadril SEMPRE pelos glúteos','Aperta glúteo no topo, pausa 1s','Erros comuns: Usar lombar pra empurrar, Hiperextensão da lombar']::text[],'beginner','principal',true),
('manual_single_leg_glute_bridge','Single Leg Glute Bridge','Ponte Unilateral','pernas','glúteo','peso_corporal',null,ARRAY['Ponte com uma perna só, outra estendida. Glúteo individual e core.','Deitado, uma perna apoiada e outra estendida','Eleva quadril pela perna apoiada','Pelve estável','Erros comuns: Pelve descompensada, Usar perna estendida pra impulsionar']::text[],'intermediate','principal',true),
('manual_plank_frontal','Plank','Prancha Frontal','core','abdomen, core profundo','peso_corporal',null,ARRAY['Posição isométrica de prancha com apoio de antebraços. Core fundamental.','Apoia antebraços e pés, corpo reto','Aperta glúteo e core','Olha pra baixo (queixo recolhido)','Erros comuns: Quadril alto, Lombar afundando, Prender respiração']::text[],'beginner','principal',true),
('manual_plank_lateral','Side Plank','Prancha Lateral','core','oblíquos','peso_corporal',null,ARRAY['Prancha de lado, apoio em 1 antebraço e 1 pé. Oblíquos.','Cotovelo abaixo do ombro','Corpo COMPLETAMENTE reto','Quadril elevado','Erros comuns: Quadril caindo, Ombro próximo da orelha']::text[],'beginner','principal',true),
('manual_mountain_climber','Mountain Climber','Mountain Climber','full_body','core, cardio','peso_corporal',null,ARRAY['Em prancha alta, alterna joelhos em direção ao peito. Cardio + core.','Posição de prancha alta','Joelho em direção ao peito, alterna rápido','Quadril estável','Erros comuns: Quadril subindo demais, Pés batendo forte']::text[],'beginner','principal',true),
('manual_burpee_sem_pular','Modified Burpee','Burpee Modificado (Sem Salto)','full_body','cardio, corpo todo','peso_corporal',null,ARRAY['Burpee sem o salto final. Iniciante pra cardio + força.','Em pé → agacha → mãos no chão','Pula pés pra trás em prancha','Pula pés pra frente, levanta sem pular','Erros comuns: Movimentos desconectados, Sem manter core na prancha']::text[],'beginner','preparatorio',true),
('manual_burpee_completo','Burpee','Burpee Completo','full_body','cardio, corpo todo','peso_corporal',null,ARRAY['Burpee tradicional com salto vertical e palmas no topo.','Movimento fluido: agacha → prancha → flexão → pé pra frente → salta','Saltar com braços pra cima','Pousar suave','Erros comuns: Pular sem amortecimento, Não fazer a flexão']::text[],'intermediate','principal',true),
('manual_bird_dog','Bird Dog','Bird Dog','core','core, glúteo','peso_corporal',null,ARRAY['Em 4 apoios, estende braço e perna opostos. Estabilidade de core.','Quatro apoios alinhados','Estende braço direito + perna esquerda','Quadril estável','Erros comuns: Quadril rotacionando, Lombar arqueada']::text[],'beginner','principal',true),
('manual_dead_bug','Dead Bug','Dead Bug','core','core, abdomen','peso_corporal',null,ARRAY['Deitado, estende braço e perna opostos sem deixar lombar sair do chão.','Deitado, joelhos a 90°, braços pro teto','Estende braço esquerdo + perna direita','Lombar PRESA no chão','Erros comuns: Lombar saindo do chão, Movimento rápido demais']::text[],'beginner','principal',true),
('manual_hollow_body_hold','Hollow Body Hold','Hollow Body Hold','core','abdomen, core profundo','peso_corporal',null,ARRAY['Posição de barco invertido. Isométrico de core profundo.','Deitado, braços atrás','Pernas estendidas 15-30cm do chão','Lombar PRESA','Erros comuns: Lombar saindo do chão, Pernas muito altas']::text[],'intermediate','principal',true),
('manual_russian_twist','Russian Twist','Russian Twist','core','oblíquos','peso_corporal',null,ARRAY['Sentado em V, gira tronco pra cada lado. Oblíquos.','Sentado, joelhos dobrados','Tronco inclinado ~45°','Gira tronco e toca o chão dos dois lados','Erros comuns: Apenas mover braços, Lombar arredondada']::text[],'beginner','principal',true),
('manual_jumping_jack','Jumping Jack','Polichinelo','full_body','cardio','peso_corporal',null,ARRAY['Salto abrindo e fechando braços e pernas. Aquecimento e cardio leve.','Ritmo constante','Braços vão ATÉ acima da cabeça','Pés se afastam até largura dos ombros','Erros comuns: Movimento parcial, Pés muito juntos']::text[],'beginner','principal',true),
('manual_pull_down_elastico','Band Pull-Down','Pull-Down com Elástico','costas','latíssimo','elastico',null,ARRAY['Puxada vertical com elástico fixado em ponto alto.','Fixe elástico em ponto alto','Puxa em direção ao peito, cotovelos descendo','Escápulas retraídas no fim','Erros comuns: Movimento só de braço, Tronco inclinado demais']::text[],'beginner','principal',true),
('manual_row_elastico','Band Row','Remada com Elástico','costas','trapézio médio, romboides','elastico',null,ARRAY['Remada horizontal com elástico. Trabalha costas média.','Fixe elástico na altura do peito','Puxa cotovelos em direção às costelas','Aperta escápulas','Erros comuns: Cotovelos abrindo, Tronco oscilando']::text[],'beginner','principal',true),
('manual_shoulder_press_elastico','Band Shoulder Press','Desenvolvimento de Ombro com Elástico','ombros','deltoides','elastico',null,ARRAY['Press acima da cabeça com elástico sob os pés.','Elástico passa sob os pés','Mãos na altura dos ombros','Empurra reto pra cima','Erros comuns: Arquear lombar, Não estender completamente']::text[],'beginner','principal',true),
('manual_face_pull_elastico','Band Face Pull','Face Pull com Elástico','ombros','deltoide posterior, trapézio médio','elastico',null,ARRAY['Puxada com elástico na altura do rosto. Saúde postural.','Elástico na altura do rosto','Puxa em direção às orelhas, cotovelos altos','Escápulas juntas','Erros comuns: Cotovelos baixos, Sem retração escapular']::text[],'beginner','principal',true),
('manual_bicep_curl_elastico','Band Bicep Curl','Rosca Bíceps com Elástico','costas','bíceps','elastico',null,ARRAY['Flexão de cotovelo com elástico sob os pés.','Elástico sob os pés, pegada supinada','Cotovelos COLADOS ao corpo','Sobe controlado até quase tocar ombro','Erros comuns: Cotovelos balançando, Usar tronco pra impulsionar']::text[],'beginner','principal',true),
('manual_tricep_extension_elastico','Band Tricep Extension','Extensão de Tríceps com Elástico','peito','tríceps','elastico',null,ARRAY['Extensão acima da cabeça com elástico.','Elástico atrás do corpo','Cotovelos APONTAM PRO TETO, fixos','Estende apenas o antebraço','Erros comuns: Cotovelos abrindo, Movimento de ombro']::text[],'beginner','principal',true),
('manual_lateral_raise_elastico','Band Lateral Raise','Elevação Lateral com Elástico','ombros','deltoide médio','elastico',null,ARRAY['Elevação dos braços lateralmente com elástico sob os pés.','Elástico sob os pés','Eleva braços lateralmente até altura dos ombros','Cotovelos levemente flexionados','Erros comuns: Elevar acima dos ombros, Usar tronco pra impulsionar']::text[],'beginner','principal',true),
('manual_good_morning_elastico','Band Good Morning','Good Morning com Elástico','pernas','posterior coxa, lombar','elastico',null,ARRAY['Inclinação do tronco à frente com elástico nos ombros.','Elástico passa pelos pés e por trás do pescoço','Quadril vai pra trás, tronco inclina à frente','Volta ao apertar glúteos','Erros comuns: Arredondar lombar, Flexionar joelhos demais']::text[],'beginner','principal',true),
('manual_jab_direto','Jab','Jab Direto','boxe','ombros, core','saco_pancada',null,ARRAY['Soco reto com a mão da frente.','Postura: pé da frente apontando pro saco','Soco em linha reta saindo do queixo','Rotação leve do quadril','Erros comuns: Soco em arco, Cotovelo levantado (vira gancho)']::text[],'beginner','principal',true),
('manual_cross_direto','Cross','Cross (Direto Forte)','boxe','ombros, core, quadril','saco_pancada',null,ARRAY['Soco reto com a mão de trás.','Rotação completa do quadril e pé traseiro','Soco em linha reta','Mão da frente protege o queixo','Erros comuns: Não rotacionar o corpo, Soltar a mão da frente']::text[],'beginner','principal',true),
('manual_hook_esquerdo','Left Hook','Hook Esquerdo','boxe','ombros, oblíquos','saco_pancada',null,ARRAY['Gancho horizontal com a mão esquerda.','Cotovelo levantado em 90°','Rotação do quadril pra esquerda','Soco horizontal','Erros comuns: Cotovelo baixo, Sem rotação']::text[],'beginner','principal',true),
('manual_hook_direito','Right Hook','Hook Direito','boxe','ombros, oblíquos','saco_pancada',null,ARRAY['Gancho horizontal com a mão direita.','Cotovelo levantado em 90°','Rotação completa do quadril direito','Soco horizontal forte','Erros comuns: Soco curto, Sem rotação']::text[],'beginner','principal',true),
('manual_uppercut','Uppercut','Uppercut','boxe','ombros, bíceps, core','saco_pancada',null,ARRAY['Soco ascendente, vindo de baixo pra cima.','Joelho levemente flexionado','Punho sobe verticalmente','Rotação do tronco amplifica','Erros comuns: Cotovelo afastado do corpo, Soco muito longo']::text[],'beginner','principal',true),
('manual_combo_1_2','Combo 1-2','Combo 1-2 (Jab + Cross)','boxe','ombros, core, quadril','saco_pancada',null,ARRAY['Sequência: jab seguido de cross.','Jab rápido','Cross forte','Voltar à guarda imediatamente','Erros comuns: Pausa entre jab e cross, Soltar a guarda']::text[],'beginner','principal',true),
('manual_combo_1_2_3','Combo 1-2-3','Combo 1-2-3 (Jab + Cross + Hook)','boxe','ombros, core, quadril','saco_pancada',null,ARRAY['Sequência: jab, cross e gancho.','Jab → Cross → Hook esquerdo (pra destro)','Peso transferido entre socos','Velocidade crescente','Erros comuns: Quebrar o ritmo, Sem rotação no hook']::text[],'intermediate','principal',true),
('manual_esquiva_jab','Slip + Jab','Esquiva + Jab','boxe','ombros, core','saco_pancada',null,ARRAY['Esquiva lateral seguida de jab.','Esquiva lateral (dobra joelho do lado)','Imediatamente jab da posição esquivada','Volta à guarda','Erros comuns: Esquiva apenas com cabeça, Demora pra contra-atacar']::text[],'intermediate','principal',true);